@code {
    [Parameter, EditorRequired] public List<Reference> References { get; set; } = [];
    [Parameter] public EventCallback<List<Reference>> OnChanged { get; set; }
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }

    private string? ErrorMessage;

    private async Task UpdateReference(int index, Reference updated)
    {
        var list = new List<Reference>(References) { [index] = updated };
        await OnChanged.InvokeAsync(list);
    }

    private async Task RemoveReference(int index)
    {
        var list = new List<Reference>(References);
        list.RemoveAt(index);
        await OnChanged.InvokeAsync(list);
    }

    private async Task AddReference()
    {
        if (References.Count >= 3) return;
        var list = new List<Reference>(References)
        {
            new("", "", "", "")
        };
        await OnChanged.InvokeAsync(list);
    }

    private async Task HandleNext()
    {
        ErrorMessage = null;

        if (References.Count < 2)
        {
            ErrorMessage = "At least 2 references are required.";
            return;
        }

        foreach (var r in References)
        {
            if (string.IsNullOrWhiteSpace(r.Name) ||
                string.IsNullOrWhiteSpace(r.Relationship) ||
                string.IsNullOrWhiteSpace(r.Email) ||
                string.IsNullOrWhiteSpace(r.Phone))
            {
                ErrorMessage = "All fields are required for each reference.";
                return;
