@* Displays the wizard progress bar with step labels, checkmarks, and click-to-navigate *@

<nav class="step-indicator mb-4">
    <ol class="d-flex list-unstyled justify-content-between position-relative px-0">
        @for (int i = 0; i < StepLabels.Length; i++)
        {
            var stepIndex = i;
            var isCurrent = stepIndex == CurrentStep;
            var isCompleted = CompletedSteps.Contains(stepIndex);
            var isFuture = !isCurrent && !isCompleted;

            <li class="step-item text-center flex-fill @(isCurrent ? "active" : "") @(isCompleted ? "completed" : "") @(isFuture ? "future" : "")"
                @onclick="() => OnStepClicked(stepIndex)"
                style="cursor: @(isCompleted ? "pointer" : "default")">
                <div class="step-circle mx-auto mb-1 d-flex align-items-center justify-content-center rounded-circle
                            @(isCurrent ? "bg-primary text-white" : isCompleted ? "bg-success text-white" : "bg-light text-muted border")"
                     style="width:36px; height:36px; font-size:0.9rem;">
                    @if (isCompleted)
                    {
                        <span>&#10003;</span>
                    }
                    else
                    {
                        <span>@(stepIndex + 1)</span>
                    }
                </div>
                <small class="@(isCurrent ? "fw-bold text-primary" : isCompleted ? "text-success" : "text-muted")">
                    @StepLabels[stepIndex]
                </small>
            </li>
        }
    </ol>
</nav>

@code {
    private static readonly string[] StepLabels =
        ["Personal Info", "Work History", "References", "Cover Letter", "Review & Submit"];

    [Parameter, EditorRequired] public int CurrentStep { get; set; }
    [Parameter, EditorRequired] public HashSet<int> CompletedSteps { get; set; } = [];
    [Parameter] public EventCallback<int> OnNavigate { get; set; }

    private async Task OnStepClicked(int step)
    {
        if (CompletedSteps.Contains(step))
        {
            await OnNavigate.InvokeAsync(step);
        }
    }
}

