@* Editable card for a single work history entry *@

<div class="card mb-3">
    <div class="card-body">
        <div class="d-flex justify-content-between align-items-start mb-2">
            <h6 class="card-title mb-0">Position @(Index + 1)</h6>
            @if (CanRemove)
            {
                <button type="button" class="btn btn-outline-danger btn-sm" @onclick="OnRemove">Remove</button>
            }
        </div>

        <div class="row g-3">
            <div class="col-md-6">
                <label class="form-label">Company Name <span class="text-danger">*</span></label>
                <input class="form-control" value="@Entry.Company"
                       @onchange="e => Update(Entry with { Company = (string?)e.Value ?? "" })" />
            </div>
            <div class="col-md-6">
                <label class="form-label">Job Title <span class="text-danger">*</span></label>
                <input class="form-control" value="@Entry.Title"
                       @onchange="e => Update(Entry with { Title = (string?)e.Value ?? "" })" />
            </div>
            <div class="col-md-4">
                <label class="form-label">Start Date <span class="text-danger">*</span></label>
                <input type="date" class="form-control" value="@Entry.StartDate.ToString("yyyy-MM-dd")"
                       @onchange="e => Update(Entry with { StartDate = DateTime.Parse((string?)e.Value ?? DateTime.Today.ToString("yyyy-MM-dd")) })" />
            </div>
            <div class="col-md-4">
                <label class="form-label">End Date</label>
                <input type="date" class="form-control" value="@Entry.EndDate?.ToString("yyyy-MM-dd")"
                       disabled="@IsCurrent"
                       @onchange="e => Update(Entry with { EndDate = DateTime.TryParse((string?)e.Value, out var d) ? d : null })" />
            </div>
            <div class="col-md-4 d-flex align-items-end">
                <div class="form-check mb-2">
                    <input class="form-check-input" type="checkbox" id="@($"current-{Index}")"
                           checked="@IsCurrent" @onchange="ToggleCurrent" />
                    <label class="form-check-label" for="@($"current-{Index}")">Currently working here</label>
                </div>
            </div>
            <div class="col-12">
                <label class="form-label">Description</label>
                <textarea class="form-control" rows="3" value="@Entry.Description"
                          @onchange="e => Update(Entry with { Description = (string?)e.Value ?? "" })"></textarea>
            </div>
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public WorkEntry Entry { get; set; } = default!;
    [Parameter] public int Index { get; set; }
    [Parameter] public bool CanRemove { get; set; }
    [Parameter] public EventCallback<WorkEntry> OnChanged { get; set; }
    [Parameter] public EventCallback OnRemove { get; set; }

    private bool IsCurrent => Entry.EndDate is null;

    private async Task Update(WorkEntry updated) => await OnChanged.InvokeAsync(updated);

    private async Task ToggleCurrent(ChangeEventArgs e)
    {
        var current = (bool?)e.Value ?? false;
        var updated = current
            ? Entry with { EndDate = null }
            : Entry with { EndDate = DateTime.Today };
        await OnChanged.InvokeAsync(updated);
    }
}

@* Step 1: Personal information form with email validation *@

<h4 class="mb-3">Personal Information</h4>

@if (!string.IsNullOrEmpty(ErrorMessage))
{
    <div class="alert alert-danger">@ErrorMessage</div>
}

<div class="row g-3">
    <div class="col-md-6">
        <label class="form-label">Full Name <span class="text-danger">*</span></label>
        <input class="form-control" value="@Info.FullName"
               @onchange="e => UpdateField(Info with { FullName = (string?)e.Value ?? "" })" />
    </div>
    <div class="col-md-6">
        <label class="form-label">Email <span class="text-danger">*</span></label>
        <input type="email" class="form-control" value="@Info.Email"
               @onchange="e => UpdateField(Info with { Email = (string?)e.Value ?? "" })" />
    </div>
    <div class="col-md-6">
        <label class="form-label">Phone <span class="text-danger">*</span></label>
        <input type="tel" class="form-control" value="@Info.Phone"
               @onchange="e => UpdateField(Info with { Phone = (string?)e.Value ?? "" })" />
    </div>
    <div class="col-md-6">
        <label class="form-label">Address <span class="text-danger">*</span></label>
        <input class="form-control" value="@Info.Address"
               @onchange="e => UpdateField(Info with { Address = (string?)e.Value ?? "" })" />
    </div>
</div>

<div class="d-flex justify-content-end mt-4">
    <button class="btn btn-primary" @onclick="HandleNext" disabled="@IsValidating">
        @if (IsValidating)
        {
            <span class="spinner-border spinner-border-sm me-1"></span>
        }
        Next
    </button>
</div>

@code {
    [Parameter, EditorRequired] public PersonalInfo Info { get; set; } = default!;
    [Parameter] public EventCallback<PersonalInfo> OnChanged { get; set; }
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter, EditorRequired] public IApplicationService ApplicationService { get; set; } = default!;

    private string? ErrorMessage;
    private bool IsValidating;

    private async Task UpdateField(PersonalInfo updated)
    {
        ErrorMessage = null;
        await OnChanged.InvokeAsync(updated);
    }

    private async Task HandleNext()
    {
        ErrorMessage = null;

        if (string.IsNullOrWhiteSpace(Info.FullName) ||
            string.IsNullOrWhiteSpace(Info.Email) ||
            string.IsNullOrWhiteSpace(Info.Phone) ||
            string.IsNullOrWhiteSpace(Info.Address))
        {
            ErrorMessage = "All fields are required.";
            return;
        }

        IsValidating = true;
        try
        {
            var emailValid = await ApplicationService.ValidateEmailAsync(Info.Email);
            if (!emailValid)
            {
                ErrorMessage = "The email address is not valid.";
                return;
            }

            await OnNext.InvokeAsync();
        }
        finally
        {
            IsValidating = false;
        }
    }
}

