toolArgs.file_text:
@* Step 5: Read-only review of all sections with edit links and submit *@

<h4 class="mb-3">Review &amp; Submit</h4>

@if (SubmittedId.HasValue)
{
    <div class="alert alert-success">
        <h5 class="alert-heading">Application Submitted!</h5>
        <p class="mb-0">Your application has been submitted successfully. Your application ID is <strong>#@SubmittedId</strong>.</p>
    </div>
}
else
{
    @if (!string.IsNullOrEmpty(ErrorMessage))
    {
        <div class="alert alert-danger">@ErrorMessage</div>
    }

    @* Personal Info Section *@
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Personal Information</strong>
            <a href="#" @onclick="() => OnEditStep.InvokeAsync(0)" @onclick:preventDefault>Edit</a>
        </div>
        <div class="card-body">
            <div class="row">
                <div class="col-md-6"><strong>Name:</strong> @Personal.FullName</div>
                <div class="col-md-6"><strong>Email:</strong> @Personal.Email</div>
                <div class="col-md-6"><strong>Phone:</strong> @Personal.Phone</div>
                <div class="col-md-6"><strong>Address:</strong> @Personal.Address</div>
            </div>
        </div>
    </div>

    @* Work History Section *@
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Work History</strong>
            <a href="#" @onclick="() => OnEditStep.InvokeAsync(1)" @onclick:preventDefault>Edit</a>
        </div>
        <div class="card-body">
            @foreach (var entry in WorkEntries)
            {
                <div class="mb-3 pb-3 border-bottom">
                    <div><strong>@entry.Title</strong> at @entry.Company</div>
                    <div class="text-muted">
                        @entry.StartDate.ToString("MMM yyyy") &mdash;
                        @(entry.EndDate.HasValue ? entry.EndDate.Value.ToString("MMM yyyy") : "Present")
                    </div>
                    @if (!string.IsNullOrWhiteSpace(entry.Description))
                    {
                        <div class="mt-1">@entry.Description</div>
                    }
                </div>
            }
        </div>
    </div>

    @* References Section *@
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>References</strong>
            <a href="#" @onclick="() => OnEditStep.InvokeAsync(2)" @onclick:preventDefault>Edit</a>
        </div>
        <div class="card-body">
            @foreach (var r in References)
            {
                <div class="mb-2">
                    <strong>@r.Name</strong> (@r.Relationship) &mdash; @r.Email, @r.Phone
                </div>
            }
        </div>
    </div>

    @* Cover Letter Section *@
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Cover Letter</strong>
            <a href="#" @onclick="() => OnEditStep.InvokeAsync(3)" @onclick:preventDefault>Edit</a>
        </div>
        <div class="card-body">
            <p style="white-space: pre-wrap;">@CoverLetter</p>
        </div>
    </div>

    <div class="d-flex justify-content-between mt-4">
        <button class="btn btn-secondary" @onclick="OnBack">Back</button>
        <button class="btn btn-success btn-lg" @onclick="HandleSubmit" disabled="@IsSubmitting">
            @if (IsSubmitting)
            {
                <span class="spinner-border spinner-border-sm me-1"></span>
            }
            Submit Application
        </button>
    </div>
}

@code {
    [Parameter, EditorRequired] public PersonalInfo Personal { get; set; } = default!;
    [Parameter, EditorRequired] public List<WorkEntry> WorkEntries { get; set; } = [];
    [Parameter, EditorRequired] public List<Reference> References { get; set; } = [];
    [Parameter, EditorRequired] public string CoverLetter { get; set; } = "";
    [Parameter] public EventCallback<int> OnEditStep { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }
    [Parameter] public EventCallback<int> OnSubmitted { get; set; }
    [Parameter, EditorRequired] public IApplicationService ApplicationService { get; set; } = default!;

    private bool IsSubmitting;
    private int? SubmittedId;
    private string? ErrorMessage;

    private async Task HandleSubmit()
    {
        IsSubmitting = true;
        ErrorMessage = null;

        try
        {
            var application = new JobApplication(
                Personal,
                new WorkHistory(WorkEntries),
                References,
                CoverLetter);

            SubmittedId = await ApplicationService.SubmitApplicationAsync(application);
            await OnSubmitted.InvokeAsync(SubmittedId.Value);
        }
        catch (Exception ex)
        {
            ErrorMessage = $"Submission failed: {ex.Message}";
        }
        finally
        {
            IsSubmitting = false;
        }
    }
}

