@page "/apply"
@rendermode InteractiveServer
@using sv_55a70a9d26ba4d439f7c7040b189ec2d.Components.Pages.Apply
@inject IApplicationService ApplicationService

<PageTitle>Job Application</PageTitle>

<div class="container py-4" style="max-width: 800px;">
    <h2 class="mb-4">Job Application</h2>

    <StepIndicator CurrentStep="@currentStep"
                   CompletedSteps="@completedSteps"
                   OnNavigate="GoToStep" />

    @switch (currentStep)
    {
        case 0:
            <PersonalInfoStep Info="@personalInfo"
                              OnChanged="info => personalInfo = info"
                              OnNext="() => CompleteAndAdvance(0)"
                              ApplicationService="@ApplicationService" />
            break;

        case 1:
            <WorkHistoryStep Entries="@workEntries"
                             OnChanged="entries => workEntries = entries"
                             OnNext="() => CompleteAndAdvance(1)"
                             OnBack="() => GoToStep(0)" />
            break;

        case 2:
            <ReferencesStep References="@references"
